-- Patchnote 0.7.0 — idempotent seed (ON CONFLICT DO NOTHING): a dev DB may already carry
-- the 0.7.0 row from a manual seed of docs/patchnote-070-draft.sql, and we want the migration
-- to be a no-op in that case instead of failing the UNIQUE constraint on version.
INSERT INTO "Patchnote" ("version", "type", "date", "titleEn", "titleFr", "entries") VALUES
('0.7.0', 'minor', '2026-04-22T00:00:00.000Z',
  'Security hardening, a11y pass & plugin CSS isolation',
  'Durcissement sécurité, a11y & isolation CSS plugins',
  '[{"type":"feat","titleEn":"Security headers (Helmet)","titleFr":"En-têtes de sécurité (Helmet)","descEn":"Strict CSP, X-Frame-Options DENY, Referrer-Policy, X-Content-Type-Options, HSTS when behind HTTPS. Closes the most common XSS/clickjacking blast radius.","descFr":"CSP strict, X-Frame-Options DENY, Referrer-Policy, X-Content-Type-Options, HSTS derrière HTTPS. Ferme la plupart des vecteurs XSS/clickjacking."},{"type":"feat","titleEn":"Signed backups + re-auth on restore","titleFr":"Sauvegardes signées + re-auth à la restauration","descEn":"Backups are HMAC-signed at creation. A tampered archive fails verification on restore. Admin now re-enters their password to apply a restore.","descFr":"Les sauvegardes sont signées HMAC à la création. Une archive modifiée est refusée à la restauration. L''admin doit re-saisir son mot de passe pour appliquer un restore."},{"type":"feat","titleEn":"Service secrets masking","titleFr":"Masquage des secrets services","descEn":"GET /admin/services no longer returns plaintext API keys/tokens. A reveal endpoint exposes the value on explicit admin action, logged for audit.","descFr":"GET /admin/services ne renvoie plus les clés API/tokens en clair. Un endpoint de reveal expose la valeur à la demande, avec trace dans les logs."},{"type":"feat","titleEn":"CSRF + SSRF guards","titleFr":"Guards CSRF + SSRF","descEn":"Admin mutations require X-Requested-With: oscarr. Service URLs are checked against private-IP ranges — permissive by default for self-hosted LAN setups, opt-in strict mode for shared hosting.","descFr":"Les mutations admin exigent X-Requested-With: oscarr. Les URLs service sont validées contre les plages IP privées — permissif par défaut pour du self-hosted LAN, mode strict opt-in pour hébergement partagé."},{"type":"feat","titleEn":"Rate-limiting on mutations","titleFr":"Limitation de débit sur les mutations","descEn":"POST /requests, /requests/collection, /admin/sync/force, /admin/restart, Plex PIN, Discord OAuth — all capped to prevent spam and DoS.","descFr":"POST /requests, /requests/collection, /admin/sync/force, /admin/restart, Plex PIN, Discord OAuth — tous limités pour empêcher spam et DoS."},{"type":"feat","titleEn":"Plugin CSS isolation","titleFr":"Isolation CSS des plugins","descEn":"Plugin stylesheets are scoped to the plugin''s DOM subtree. Installing one no longer leaks Tailwind utilities into the rest of the app.","descFr":"Les feuilles de style des plugins sont scopées à leur sous-arbre DOM. Installer un plugin ne propage plus ses utilitaires Tailwind au reste de l''app."},{"type":"feat","titleEn":"Update banner in sidebar","titleFr":"Bannière de mise à jour dans la sidebar","descEn":"When a new Oscarr release lands on GitHub, the admin sidebar surfaces a one-click link to the release notes.","descFr":"Quand une nouvelle version Oscarr arrive sur GitHub, la sidebar admin affiche un lien direct vers les release notes."},{"type":"feat","titleEn":"Accessibility pass","titleFr":"Passe d''accessibilité","descEn":"Focus-visible rings everywhere, aria-labels on icon buttons, a useModal hook (Escape + focus-trap + focus-return) applied across the app, skip-to-content link, screen-reader-announced toasts.","descFr":"Focus visible partout, aria-label sur les boutons icon-only, hook useModal (Escape + piège de focus + retour) appliqué partout, lien saut au contenu, toasts annoncés aux lecteurs d''écran."},{"type":"perf","titleEn":"Admin bundle code-splitting","titleFr":"Code-splitting du bundle admin","descEn":"Non-admin users no longer download the admin UI upfront. Services editor, query builder, plugin manager load on demand — initial bundle cut by 2-3x.","descFr":"Les utilisateurs non-admin ne téléchargent plus l''UI admin au démarrage. Éditeur de services, query builder, gestionnaire de plugins chargés à la demande — bundle initial divisé par 2-3×."},{"type":"perf","titleEn":"Frontend & data wins","titleFr":"Gains frontend & données","descEn":"Memoized AuthContext, stable handlers on infinite-scrolled RequestCards, NSFW filter via SQLite json_each + in-process cache, leaner /requests payloads (~40% smaller), polling paused when the tab is hidden, Prisma indexes on media status/availability/service IDs.","descFr":"AuthContext mémoïsé, handlers stables sur les cards en scroll infini, filtre NSFW via SQLite json_each + cache in-process, payloads /requests allégés (~40%), polling en pause quand l''onglet est caché, indexes Prisma sur status/availableAt/serviceIds."},{"type":"refactor","titleEn":"Backend architecture cleanup","titleFr":"Nettoyage architecture backend","descEn":"Backup + push extracted to services/, breaking the service→route dependency cycle. TMDB route collapsed to 17 lines via a shared fetchList helper. Requests routes split into create/lifecycle/list/maintenance.","descFr":"Backup + push extraits dans services/, cycle de dépendance service→route cassé. Route TMDB réduite à 17 lignes via un helper fetchList partagé. Routes requests splittées en create/lifecycle/list/maintenance."},{"type":"refactor","titleEn":"Admin tabs modularized + per-plugin Tailwind","titleFr":"Tabs admin modularisés + Tailwind par plugin","descEn":"PluginsTab and ServicesTab split into hook + presentational components (<200 LoC each). Plugins now compile their own Tailwind bundle via a shared preset — no more purged utility classes.","descFr":"PluginsTab et ServicesTab découpés en hook + composants présentationnels (<200 lignes chacun). Les plugins compilent maintenant leur propre bundle Tailwind via un preset partagé — plus d''utilities purgées."},{"type":"feat","titleEn":"Nightly release channel","titleFr":"Canal de release nightly","descEn":"Release workflow supports a nightly dispatch — push :nightly images to test in your own prod without hijacking :latest consumers. Pre-release tags (v1.0.0-rc.1) no longer alias :latest either.","descFr":"Le workflow de release supporte un mode nightly — push d''images :nightly pour tester en prod perso sans impacter les consommateurs de :latest. Les tags pre-release (v1.0.0-rc.1) n''aliasent plus :latest."},{"type":"fix","titleEn":"Dependency patches","titleFr":"Patches de dépendances","descEn":"serialize-javascript RCE and follow-redirects header leak patched via npm overrides. Zero high/moderate vulnerabilities reported by npm audit.","descFr":"RCE serialize-javascript et fuite header follow-redirects patchés via npm overrides. Zéro vulnérabilité high/moderate rapportée par npm audit."},{"type":"fix","titleEn":"Stability fixes","titleFr":"Correctifs de stabilité","descEn":"Rules-of-Hooks violations in RolesTab and KeywordsTab TagCell resolved. Backup path resolution fixed after the service extraction. Service test errors now distinguish SSRF blocks from genuine connectivity failures.","descFr":"Violations Rules-of-Hooks dans RolesTab et KeywordsTab TagCell corrigées. Résolution du chemin backup après l''extraction du service. Les erreurs de test service distinguent maintenant les blocages SSRF des vrais échecs de connectivité."}]'
) ON CONFLICT ("version") DO NOTHING;
